DECLARE
LV_DELETED_TXN_CNT NUMBER DEFAULT 0;
BEGIN
SELECT COUNT(1) INTO LV_DELETED_TXN_CNT FROM <?=odiRef.getSchemaName("CCAL_REPL_OWNER", "D") ?>.J$AVY_FACT where JRN_SUBSCRIBER=:GLOBAL.MONITOR_SUBCRIBER_NAME and THREAD_NO= :GLOBAL.GV_RT_THRD_NO AND JRN_CONSUMED = 'Y' AND NVL(NUMBER_OF_ATTEMPTS,0) <:GLOBAL.GV_RT_NUMBER_OF_ATTEMPTS AND JRN_FLAG= 'D';
IF LV_DELETED_TXN_CNT > 0 THEN
DELETE FROM <?=odiRef.getSchemaName("TRANSACTIONS_OWNER", "D") ?>.#SSDS.SSDS_AVY_FACT_TABLE_NAME WHERE TXN_ID IN ( SELECT TXN_ID FROM <?=odiRef.getSchemaName("CCAL_REPL_OWNER", "D") ?>.J$AVY_FACT where JRN_SUBSCRIBER=:GLOBAL.MONITOR_SUBCRIBER_NAME and THREAD_NO= :GLOBAL.GV_RT_THRD_NO AND JRN_CONSUMED = 'Y' AND NVL(NUMBER_OF_ATTEMPTS,0) <:GLOBAL.GV_RT_NUMBER_OF_ATTEMPTS AND JRN_FLAG= 'D' );
-- Log activity into avy_fact_log table for publishing to lighthouse INSERT INTO <?=odiRef.getSchemaName("TRANSACTIONS_OWNER", "D") ?>.AVY_FACT_LOG ( TXN_ID, JRN_FLAG, CRT_DTM, CRT_USR_NM, LAST_UDT_DTM, LAST_UDT_USR_NM ) select TXN_ID, JRN_FLAG, sysdate, '<?=odiRef.getSession("SESS_NAME") ?>', sysdate, '<?=odiRef.getSession("SESS_NAME") ?>' FROM <?=odiRef.getSchemaName("CCAL_REPL_OWNER", "D") ?>.J$AVY_FACT where JRN_SUBSCRIBER=:GLOBAL.MONITOR_SUBCRIBER_NAME and THREAD_NO= :GLOBAL.GV_RT_THRD_NO AND NVL(NUMBER_OF_ATTEMPTS,0) < :GLOBAL.GV_RT_NUMBER_OF_ATTEMPTS AND JRN_CONSUMED = 'Y' AND JRN_FLAG= 'D';
DELETE FROM <?=odiRef.getSchemaName("CCAL_REPL_OWNER", "D") ?>.J$AVY_FACT where JRN_SUBSCRIBER=:GLOBAL.MONITOR_SUBCRIBER_NAME and THREAD_NO= :GLOBAL.GV_RT_THRD_NO AND JRN_CONSUMED = 'Y' AND NVL(NUMBER_OF_ATTEMPTS,0) <:GLOBAL.GV_RT_NUMBER_OF_ATTEMPTS AND JRN_FLAG= 'D';
END IF;
END;

DECLARE
  V_SQL         VARCHAR2(4000);
  TABLE_NAMES   VARCHAR2(4000):='CCAL_REPL_OWNER.J$AVY_FACT';
  V_TABLE       VARCHAR2(65);
  V_TABLE_NAME  VARCHAR2(30);
  V_TABLE_OWNER VARCHAR2(30);
  V_PART_NAME   VARCHAR2(30);

BEGIN
  FOR I IN (SELECT REGEXP_SUBSTR(TABLE_NAMES,'[^,]+', 1, LEVEL) TABLE_NAME FROM DUAL
CONNECT BY REGEXP_SUBSTR(TABLE_NAMES, '[^,]+', 1, LEVEL) IS NOT NULL)
    LOOP
    V_TABLE      := I.TABLE_NAME;
    V_TABLE_OWNER:=SUBSTR(V_TABLE,1,INSTR(V_TABLE,'.',1,1)-1);
    V_TABLE_NAME :=SUBSTR(V_TABLE,instr(V_TABLE,'.',1,1)   +1);
    Begin 
    SELECT PART_NAME
    INTO V_PART_NAME
    FROM
      (SELECT partition_name PART_NAME
      FROM all_tab_partitions
      WHERE table_owner=V_TABLE_OWNER
      AND table_name   =V_TABLE_NAME
      ORDER BY partition_position DESC
      )
    WHERE rownum <2;
    exception when NO_DATA_FOUND THEN V_PART_NAME:=NULL;
    end;

    V_SQL       := 'BEGIN APP_SUPPORT_OWNER.STATS_PKG.RUN_STATS( I_OWNER =>'''|| V_TABLE_OWNER  ||''', I_TABLE_NAME     => '''||V_TABLE_NAME||''',i_partition_name =>'''|| V_PART_NAME  ||'''); END;' ;
    EXECUTE IMMEDIATE V_SQL;
    --dbms_output.put_line('SQL-'||v_sql);
  END LOOP;
END;

BEGIN -- Log activity into avy_fact_log table for publishing to lighthouse INSERT INTO <?=odiRef.getSchemaName("TRANSACTIONS_OWNER", "D") ?>.AVY_FACT_LOG ( TXN_ID, JRN_FLAG, CRT_DTM, CRT_USR_NM, LAST_UDT_DTM, LAST_UDT_USR_NM ) select TXN_ID, JRN_FLAG, sysdate, '<?=odiRef.getSession("SESS_NAME") ?>', sysdate, '<?=odiRef.getSession("SESS_NAME") ?>' FROM <?=odiRef.getSchemaName("CCAL_REPL_OWNER", "D") ?>.J$AVY_FACT where JRN_SUBSCRIBER=:GLOBAL.MONITOR_SUBCRIBER_NAME and THREAD_NO= :GLOBAL.GV_RT_THRD_NO AND NVL(NUMBER_OF_ATTEMPTS,0) < :GLOBAL.GV_RT_NUMBER_OF_ATTEMPTS AND JRN_CONSUMED IN( 'Y','D') AND JRN_FLAG in ('I','U');
DELETE FROM <?=odiRef.getSchemaName("CCAL_REPL_OWNER", "D") ?>.J$AVY_FACT where JRN_SUBSCRIBER=:GLOBAL.MONITOR_SUBCRIBER_NAME AND THREAD_NO= :GLOBAL.GV_RT_THRD_NO AND JRN_CONSUMED = 'D' AND NVL(NUMBER_OF_ATTEMPTS,0) < :GLOBAL.GV_RT_NUMBER_OF_ATTEMPTS;
END;

BEGIN
ROLLBACK ;
--RAISE_APPLICATION_ERROR(-20001,'External process failure - load aborted');
END ;
